#pragma once

#include <cstdint>
#include <vector>
#include <omp.h>

namespace {

int num_threads() {
  return std::max(1, std::min(8, omp_get_max_threads()));
}

uint64_t checksum_u32(const std::vector<uint32_t>& data) {
  uint64_t hash = 1469598103934665603ULL;
  for (uint32_t v : data) {
    hash ^= static_cast<uint64_t>(v);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t histogram_checksum(const std::vector<uint8_t>& input, int bins, int iters) {
  omp_set_num_threads(num_threads());
  std::vector<uint32_t> counts(static_cast<std::size_t>(bins), 0);

  for (int iter = 0; iter < iters; ++iter) {
    std::fill(counts.begin(), counts.end(), 0u);

    std::vector<std::vector<uint32_t>> thread_counts(omp_get_max_threads(), std::vector<uint32_t>(bins, 0));

    #pragma omp parallel
    {
      int tid = omp_get_thread_num();
      std::vector<uint32_t>& local_counts = thread_counts[tid];

      #pragma omp for schedule(static)
      for (std::size_t i = 0; i < input.size(); ++i) {
        local_counts[input[i]]++;
      }
    }

    for (const auto& local : thread_counts) {
      for (int i = 0; i < bins; ++i) {
        counts[i] += local[i];
      }
    }
  }

  return checksum_u32(counts);
}
